var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"사장실, 코핀 컴퍼니\\n<color=#ffd34c>관리자</color>, 화상 회의 중\\n보안국 청사 습격 ██분 전","JPN":"社長室、コフィンカンパニー\\n<color=#ffd34c>管理者</color>、ビデオ会議中\\n保安局官庁襲撃まであと██分","ENG":"Coffin Company, The CEO's office\\n<color=#ffd34c>Administrator</color>, Video Conference\\n██ minutes before the Department of National Security is attacked","TWN":"老闆辦公室，科芬公司\\n<color=#ffd34c>管理者</color>，視訊會議中\\n偷襲安全局大樓██分鐘前","THA":"ห้อง CEO บริษัทคอฟฟิน\\n<color=#ffd34c>ผู้บริหาร</color> การประชุมทางไกลผ่านวิดีโอ\\n██ นาทีก่อนที่สำนักงานความมั่นคงแห่งชาติจะถูกโจมตี","VTN":"Công ty Coffin, Văn phòng của CEO\\n<color=#ffd34c>Quản trị viên</color>, Hội nghị truyền hình\\n ██ phút trước khi Cục An Ninh Quốc Gia bị tấn công","SCN":"老板办公室，科芬公司\\n<color=#ffd34c>管理者</color>，视频会议中\\n安全局总部袭击发生██分钟前","DEU":"Coffin Company, das Büro des CEO \\n<color=#ffd34c>Administrator</color>, Videokonferenz \\n██ Minuten vor dem Angriff des Abteilung für nationale Sicherheit","FRA":"Coffin Company, bureau du PDG\\n<color=#ffd34c>Administrateur</color>, vidéoconférence\\n██ minutes avant que le Département de la sécurité nationale ne soit attaqué"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모르스에, 마에스트로라…….","JPN":"モールスに、マエストロか……","ENG":"Mors, and Maestra...","TWN":"莫爾斯再加上指揮家……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"확실히 마에스트로는 골치 아픈 그림자라네. 매번 대처하기 곤란한 시기만 노려 움직였지.","JPN":"確かにマエストロは面倒なシャドウだ。いつも対処しにくい時期にだけ動いてたな。","ENG":"Indeed, Maestra is quite a troublesome Shadow. She only makes a move when it is difficult for me to take care of it.","TWN":"指揮家確實很令人頭疼呢，每次都專挑不好應付的時間行動。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만 핵을 파괴당했잖아. 모르스가 오인한 건 아니려나?","JPN":"でも核を破壊されたでしょう。モールスの勘違いじゃないかしら？","ENG":"But the core was destroyed. Maybe Mors was mistaken?","TWN":"不過她的核心不是已經遭到破壞嗎？還是莫爾斯誤會？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마에스트로와 같은 데모고르곤들은 이면세계에 일어나는 기상재해에 가깝다네.","JPN":"マエストロのようなデモゴルゴンは、裏世界で起きる気象災害に近い。","ENG":"Demogorgons like Maestra are like massive weather disasters to Counterside.","TWN":"像指揮家這類的魔神，就類似在異界發生的氣象災害。"},"stage":{"bg":"HARMONY_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대기의 흐름에 따라 태풍이 일어나는 것처럼, 조건이 갖춰지면 발생하게 되지.","JPN":"大気の流れによって台風が生じるように、条件が揃えば発生する。","ENG":"Just like how typhoons occur when strong winds hit certain areas of the ocean, Demogorgons occur when certain conditions are met.","TWN":"就像颱風會順著氣流形成一樣，只要條件滿足就會發生。"},"stage":{"bg":"HARMONY_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"파괴된 핵이 다시 생성되려면 아득한 시간이 걸리네만, 이번 케이스는 조금 다른 것 같군.","JPN":"破壊された核が再生成されるにはものすごく時間がかかるんだが、今度のケースは少し違うようだな。","ENG":"It normally takes a long time for the destroyed core to be re-formed, but this case seems a little different.","TWN":"通常遭破壞的核心若要復生，會需要花很長的時間，但這次似乎是個特例。"},"stage":{"bg":"HARMONY_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……트러블 슈팅 작전이 공식적으로 종결된 직후였지.","JPN":"……トラブルシューティング作戦が公式的に終結となった直後だった。","ENG":"...It was at the end of Operation Troubleshooting.","TWN":"……故障排除作戰正式結束之後，"},"stage":{"bg":"HARMONY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"현실세계에 있던 전대들이 전부 동원되어 <color=#ffd34c>이 나라</color>를 이잡듯 뒤졌어.","JPN":"現実世界にいた戦隊が全部動員されて、<color=#ffd34c>この国</color>を隅々まで探し回ったわ。","ENG":"All Divisions in Normalside were mobilized to comb through <color=#ffd34c>this very country</color> for her.","TWN":"便動員所有在現實世界的戰隊，地毯式搜查<color=#ffd34c>這個國家</color>，"},"stage":{"bg":"HARMONY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"마에스트로의 예상 도착 좌표는 바로 여기, 타나베린이었으니까.","JPN":"マエストロの予想到着座標はここ、タナベリンだったから。","ENG":"Because Maestra’s predicted arrival coordinates were right here in Tanaberin.","TWN":"結果發現指揮家的預計抵達座標就是這裡 達那貝林。"},"stage":{"bg":"HARMONY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만 소득은 없었으려나. 예상 도착 좌표에서 찾은 생존자들을 제외하면.","JPN":"でも無駄骨だったのかな。予想到着座標で見つかった生存者を除けばね。","ENG":"But to no avail. There wasn’t anyone at the predicted arrival coordinates except for those survivors.","TWN":"但是卻一無所獲，在預計抵達座標的位置只有找到倖存者。"},"stage":{"bg":"HARMONY_01","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대외적으로는 건국기념전당 폭발 사고로 알려졌지.","JPN":"対外的には建国記念館の爆発事故で知られているな。","ENG":"To the public, it was known as the National Foundation Hall Explosion.","TWN":"對外的說法是建國紀念堂爆炸事件。"},"stage":{"bg":"HARMONY_01","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 마에스트로가 현실세계로 부상하면서 일으킨 여파였는데 말이야.","JPN":"そう。実はマエストロが現実世界に浮上した余波だったんだけどね。","ENG":"Right. It was an aftereffect of Maestra’s emergence into Normalside.","TWN":"沒錯，指揮家躍入現實世界後產生的風波。"},"stage":{"bg":"HARMONY_01","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당시 정부는……. 반정부 단체의 소행이라고 주장했었나?","JPN":"当時の政府は……反政府団体の仕業だと主張したっけ？","ENG":"The government... Did they claim it as an act of the anti-government organization?","TWN":"當時……政府說是反政府團體的行為嗎？"},"stage":{"bg":"HARMONY_01","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지. 그 시절에도 이 나라의 정세는 무척 혼란스러웠다네.","JPN":"ああ。その頃もこの国の情勢は極めて混乱していた。","ENG":"Correct. Even back then, the situation in this country was that of complete chaos.","TWN":"沒錯，那時候這個國家的局勢非常混亂，"},"stage":{"bg":"HARMONY_01","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원인불명의 사고……. 생존자도 둘뿐이니 선전에 쓰기엔 안성맞춤이었을 걸세.","JPN":"原因不明の事故……生存者も二人だけだったから宣伝には打ってつけだっただろう。","ENG":"An incident of unknown causes... with only two survivors it was perfect for their propaganda machine.","TWN":"原因不明的事件……倖存者也只有2位，很適合拿來作為政治操弄。"},"stage":{"bg":"HARMONY_01","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};